B.S_=s(["True","False"],t.s)
B.PR=new A.aE("b_misc_2","dart_fundamentals","Types",B.az,B.hq,"Dart is a statically typed language.","True","Dart is statically typed with type inference. The analyzer checks types at compile time, but you can use dynamic to opt out of static checking.",B.S_,0)
B.OQ=new A.aE("b_misc_3","layouts","Themes",B.az,B.A,"How do you apply a consistent theme across a Flutter app?","Pass a ThemeData to MaterialApp's theme parameter. Access it anywhere via Theme.of(context). Override locally with Theme widget.","MaterialApp(theme: ThemeData(colorScheme: ColorScheme.fromSeed(seedColor: Colors.blue)));\nAccess: Theme.of(context).colorScheme.primary",null,null)
